import json, glob, os, re

base = "/Users/duhl/.cursor/projects/Users-duhl-git-anedot-one/agent-transcripts"
paths = []
for d in glob.glob(base + "/*"):
    if not os.path.isdir(d):
        continue
    uuid = os.path.basename(d)
    p = os.path.join(d, f"{uuid}.jsonl")
    if os.path.isfile(p):
        paths.append(p)

def extract_text(msg):
    if not msg:
        return ""
    content = msg.get("content") if isinstance(msg, dict) else msg
    if isinstance(content, str):
        return content
    if not isinstance(content, list):
        return str(content) if content else ""
    parts = []
    for block in content:
        if isinstance(block, dict) and block.get("type") == "text":
            parts.append(block.get("text", ""))
        elif isinstance(block, str):
            parts.append(block)
    return "\n".join(parts)

def clean_user(text):
    text = re.sub(r"<user_query>\s*", "", text)
    text = re.sub(r"</user_query>\s*", "", text)
    text = re.sub(r"<[^>]+>.*?</[^>]+>", "", text, flags=re.DOTALL)
    return text.strip()

for p in sorted(paths, key=os.path.getmtime):
    print("=" * 80)
    print(os.path.basename(os.path.dirname(p)))
    with open(p) as f:
        for i, line in enumerate(f, 1):
            try:
                obj = json.loads(line)
            except json.JSONDecodeError:
                continue
            if obj.get("role") != "user":
                continue
            text = clean_user(extract_text(obj.get("message")))
            if len(text) < 8:
                continue
            if len(text) > 3000:
                text = text[:3000] + "..."
            print(f"\n--- user ---")
            print(text)
